 35→/**
 36→ * Full integration tests for AuthController (M1 Auth API).
 37→ *
 38→ * Covers all 14 acceptance criteria from M1-auth.md:
 39→ * - AC1:  POST /api/auth/register with valid data -> 201
 40→ * - AC2:  POST /api/auth/register with duplicate username -> 409
 41→ * - AC3:  Password stored as bcrypt hash, not plaintext
 42→ * - AC4:  POST /api/auth/login with correct credentials -> 200 + token
 43→ * - AC5:  POST /api/auth/login with wrong password -> 401
 44→ * - AC6:  POST /api/auth/login with non-existent username -> 401
 45→ * - AC7:  GET /api/auth/me with valid token -> 200
 46→ * - AC8:  GET /api/auth/me without Authorization header -> 401
 47→ * - AC9:  GET /api/auth/me with expired token -> 401
 48→ * - AC10: GET /api/auth/me with malformed token -> 401
 49→ * - AC11: Register with username <3 or >50 chars -> 400
 50→ * - AC12: Register with password <8 chars -> 400
 51→ * - AC13: Register with empty or >100 char displayName -> 400
 52→ * - AC14: Register with non-alphanumeric username -> 400
 53→ *
 54→ * Uses @SpringBootTest + @AutoConfigureMockMvc for full end-to-end testing.
 55→ */
 56→@SpringBootTest
 57→@AutoConfigureMockMvc
 58→@ActiveProfiles("test")
 59→@Transactional
 60→@DisplayName("AuthController Integration Tests")
 61→class AuthControllerIntegrationTest {
 62→
 63→    @Autowired
 64→    private MockMvc mockMvc;
 65→
 66→    @Autowired
 67→    private ObjectMapper objectMapper;
 68→
 69→    @Autowired
 70→    private UserRepository userRepository;
 71→
 72→    @Autowired
 73→    private PasswordEncoder passwordEncoder;
 74→
 75→    @Autowired
 76→    private JwtTokenProvider jwtTokenProvider;
 77→
 78→    @Value("${app.jwt.secret}")
 79→    private String jwtSecret;
 80→
 81→    private static final String REGISTER_URL = "/api/auth/register";
 82→    private static final String LOGIN_URL = "/api/auth/login";
 83→    private static final String ME_URL = "/api/auth/me";
 84→
 85→    private String registerJson(String username, String password, String displayName) {
 86→        return String.format(
 87→                "{\"username\":\"%s\",\"password\":\"%s\",\"displayName\":\"%s\"}",
 88→                username, password, displayName
 89→        );
 90→    }
 91→
 92→    private String loginJson(String username, String password) {
 93→        return String.format(
 94→                "{\"username\":\"%s\",\"password\":\"%s\"}",
 95→                username, password
 96→        );
 97→    }
 98→
 99→    /**
100→     * Helper: register a user and return the MvcResult.
101→     */
102→    private MvcResult registerUser(String username, String password, String displayName) throws Exception {
103→        return mockMvc.perform(post(REGISTER_URL)
104→                        .contentType(MediaType.APPLICATION_JSON)
105→                        .content(registerJson(username, password, displayName)))
106→                .andReturn();
107→    }
108→
109→    /**
110→     * Helper: register a user, then login, and return the JWT token.
111→     */
112→    private String registerAndLogin(String username, String password, String displayName) throws Exception {
113→        registerUser(username, password, displayName);
114→
115→        MvcResult loginResult = mockMvc.perform(post(LOGIN_URL)
116→                        .contentType(MediaType.APPLICATION_JSON)
117→                        .content(loginJson(username, password)))
118→                .andReturn();
119→
120→        JsonNode loginBody = objectMapper.readTree(loginResult.getResponse().getContentAsString());
121→        return loginBody.get("token").asText();
122→    }
