258→    @Nested
259→    @DisplayName("AC3: Password stored as bcrypt hash")
260→    class PasswordBcryptHash {
261→
262→        @Test
263→        @DisplayName("should store password as bcrypt hash, not plaintext")
264→        void shouldStoreBcryptHash() throws Exception {
265→            String rawPassword = "mySecretPassword123";
266→
267→            mockMvc.perform(post(REGISTER_URL)
268→                            .contentType(MediaType.APPLICATION_JSON)
269→                            .content(registerJson("bcryptuser", rawPassword, "Bcrypt User")))
270→                    .andExpect(status().isCreated());
271→
272→            Optional<User> user = userRepository.findByUsername("bcryptuser");
273→            assertThat(user).isPresent();
274→
275→            String storedPassword = user.get().getPassword();
276→
277→            // Must not be plaintext
278→            assertThat(storedPassword).isNotEqualTo(rawPassword);
279→
280→            // Must be a valid bcrypt hash (starts with $2a$, $2b$, or $2y$)
281→            assertThat(storedPassword).matches("^\\$2[aby]?\\$\\d{1,2}\\$.*");
282→
283→            // Must verify against original password using bcrypt
284→            assertThat(passwordEncoder.matches(rawPassword, storedPassword)).isTrue();
285→        }
286→
287→        @Test
288→        @DisplayName("should not verify against a different password")
289→        void shouldNotVerifyDifferentPassword() throws Exception {
290→            mockMvc.perform(post(REGISTER_URL)
291→                            .contentType(MediaType.APPLICATION_JSON)
292→                            .content(registerJson("bcryptuser2", "correctPassword1", "Bcrypt User 2")))
293→                    .andExpect(status().isCreated());
294→
295→            Optional<User> user = userRepository.findByUsername("bcryptuser2");
296→            assertThat(user).isPresent();
297→
298→            assertThat(passwordEncoder.matches("wrongPassword1", user.get().getPassword())).isFalse();
299→        }
300→    }
