461→    // ── AC9: GET /api/auth/me with expired token -> 401 ──────────────────
462→
463→    @Nested
464→    @DisplayName("AC9: GET /api/auth/me with expired token")
465→    class GetMeWithExpiredToken {
466→
467→        @Test
468→        @DisplayName("should return 401 when token is expired")
469→        void shouldReturn401WithExpiredToken() throws Exception {
470→            // Register a user to get a valid user ID
471→            registerUser("expireduser", "password123", "Expired User");
472→            Optional<User> user = userRepository.findByUsername("expireduser");
473→            assertThat(user).isPresent();
474→
475→            // Build an expired token manually
476→            SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes(StandardCharsets.UTF_8));
477→            String expiredToken = Jwts.builder()
478→                    .subject(String.valueOf(user.get().getId()))
479→                    .issuedAt(new Date(System.currentTimeMillis() - 200_000))
480→                    .expiration(new Date(System.currentTimeMillis() - 100_000)) // expired 100s ago
481→                    .signWith(key)
482→                    .compact();
483→
484→            mockMvc.perform(get(ME_URL)
485→                            .header("Authorization", "Bearer " + expiredToken))
486→                    .andExpect(status().isUnauthorized());
487→        }
488→    }
