package com.taskflow.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.entity.User;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.security.Keys;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;
import org.springframework.transaction.annotation.Transactional;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.util.Date;
import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Full integration tests for AuthController (M1 Auth API).
 *
 * Covers all 14 acceptance criteria from M1-auth.md:
 * - AC1:  POST /api/auth/register with valid data -> 201
 * - AC2:  POST /api/auth/register with duplicate username -> 409
 * - AC3:  Password stored as bcrypt hash, not plaintext
 * - AC4:  POST /api/auth/login with correct credentials -> 200 + token
 * - AC5:  POST /api/auth/login with wrong password -> 401
 * - AC6:  POST /api/auth/login with non-existent username -> 401
 * - AC7:  GET /api/auth/me with valid token -> 200
 * - AC8:  GET /api/auth/me without Authorization header -> 401
 * - AC9:  GET /api/auth/me with expired token -> 401
 * - AC10: GET /api/auth/me with malformed token -> 401
 * - AC11: Register with username <3 or >50 chars -> 400
 * - AC12: Register with password <8 chars -> 400
 * - AC13: Register with empty or >100 char displayName -> 400
 * - AC14: Register with non-alphanumeric username -> 400
 *
 * Uses @SpringBootTest + @AutoConfigureMockMvc for full end-to-end testing.
 */
@SpringBootTest
@AutoConfigureMockMvc
@ActiveProfiles("test")
@Transactional
@DisplayName("AuthController Integration Tests")
class AuthControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private PasswordEncoder passwordEncoder;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @Value("${app.jwt.secret}")
    private String jwtSecret;

    private static final String REGISTER_URL = "/api/auth/register";
    private static final String LOGIN_URL = "/api/auth/login";
    private static final String ME_URL = "/api/auth/me";

    private String registerJson(String username, String password, String displayName) {
        return String.format(
                "{\"username\":\"%s\",\"password\":\"%s\",\"displayName\":\"%s\"}",
                username, password, displayName
        );
    }

    private String loginJson(String username, String password) {
        return String.format(
                "{\"username\":\"%s\",\"password\":\"%s\"}",
                username, password
        );
    }

    /**
     * Helper: register a user and return the MvcResult.
     */
    private MvcResult registerUser(String username, String password, String displayName) throws Exception {
        return mockMvc.perform(post(REGISTER_URL)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(registerJson(username, password, displayName)))
                .andReturn();
    }

    /**
     * Helper: register a user, then login, and return the JWT token.
     */
    private String registerAndLogin(String username, String password, String displayName) throws Exception {
        registerUser(username, password, displayName);

        MvcResult loginResult = mockMvc.perform(post(LOGIN_URL)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(loginJson(username, password)))
                .andReturn();

        JsonNode loginBody = objectMapper.readTree(loginResult.getResponse().getContentAsString());
        return loginBody.get("token").asText();
    }

    // ── AC1: Register with valid data -> 201 ─────────────────────────────

    @Nested
    @DisplayName("AC1: POST /api/auth/register with valid data")
    class RegisterValidData {

        @Test
        @DisplayName("should return 201 Created with id, username, displayName")
        void shouldReturn201WithUserResponse() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("testuser", "password123", "Test User")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.id").isNumber())
                    .andExpect(jsonPath("$.username").value("testuser"))
                    .andExpect(jsonPath("$.displayName").value("Test User"));
        }

        @Test
        @DisplayName("should not return password in response body")
        void shouldNotReturnPasswordInResponse() throws Exception {
            MvcResult result = mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("testuser2", "password123", "Test User 2")))
                    .andExpect(status().isCreated())
                    .andReturn();

            String body = result.getResponse().getContentAsString();
            assertThat(body).doesNotContain("password123");
            JsonNode json = objectMapper.readTree(body);
            assertThat(json.has("password")).isFalse();
        }

        @Test
        @DisplayName("should persist user in database after registration")
        void shouldPersistUserInDatabase() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("dbuser", "password123", "DB User")))
                    .andExpect(status().isCreated());

            Optional<User> user = userRepository.findByUsername("dbuser");
            assertThat(user).isPresent();
            assertThat(user.get().getUsername()).isEqualTo("dbuser");
            assertThat(user.get().getDisplayName()).isEqualTo("DB User");
        }

        @Test
        @DisplayName("should accept username with underscores and digits")
        void shouldAcceptUsernameWithUnderscoresAndDigits() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("user_123_test", "password123", "Underscore User")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.username").value("user_123_test"));
        }

        @Test
        @DisplayName("should accept username at minimum boundary (3 chars)")
        void shouldAcceptUsernameAtMinBoundary() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("abc", "password123", "Min User")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.username").value("abc"));
        }

        @Test
        @DisplayName("should accept username at maximum boundary (50 chars)")
        void shouldAcceptUsernameAtMaxBoundary() throws Exception {
            String username50 = "a".repeat(50);
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson(username50, "password123", "Max User")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.username").value(username50));
        }

        @Test
        @DisplayName("should accept password at minimum boundary (8 chars)")
        void shouldAcceptPasswordAtMinBoundary() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("minpwduser", "12345678", "Min Pwd User")))
                    .andExpect(status().isCreated());
        }

        @Test
        @DisplayName("should accept displayName at minimum boundary (1 char)")
        void shouldAcceptDisplayNameAtMinBoundary() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("dname_min", "password123", "A")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.displayName").value("A"));
        }

        @Test
        @DisplayName("should accept displayName at maximum boundary (100 chars)")
        void shouldAcceptDisplayNameAtMaxBoundary() throws Exception {
            String displayName100 = "D".repeat(100);
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("dname_max", "password123", displayName100)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.displayName").value(displayName100));
        }
    }

    // ── AC2: Register with duplicate username -> 409 ─────────────────────

    @Nested
    @DisplayName("AC2: POST /api/auth/register with existing username")
    class RegisterDuplicateUsername {

        @Test
        @DisplayName("should return 409 Conflict when username already exists")
        void shouldReturn409WhenUsernameExists() throws Exception {
            // First registration should succeed
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("duplicate", "password123", "First User")))
                    .andExpect(status().isCreated());

            // Second registration with same username should fail
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("duplicate", "otherpass123", "Second User")))
                    .andExpect(status().isConflict());
        }
    }

    // ── AC3: Password stored as bcrypt hash ──────────────────────────────

    @Nested
    @DisplayName("AC3: Password stored as bcrypt hash")
    class PasswordBcryptHash {

        @Test
        @DisplayName("should store password as bcrypt hash, not plaintext")
        void shouldStoreBcryptHash() throws Exception {
            String rawPassword = "mySecretPassword123";

            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("bcryptuser", rawPassword, "Bcrypt User")))
                    .andExpect(status().isCreated());

            Optional<User> user = userRepository.findByUsername("bcryptuser");
            assertThat(user).isPresent();

            String storedPassword = user.get().getPassword();

            // Must not be plaintext
            assertThat(storedPassword).isNotEqualTo(rawPassword);

            // Must be a valid bcrypt hash (starts with $2a$, $2b$, or $2y$)
            assertThat(storedPassword).matches("^\\$2[aby]?\\$\\d{1,2}\\$.*");

            // Must verify against original password using bcrypt
            assertThat(passwordEncoder.matches(rawPassword, storedPassword)).isTrue();
        }

        @Test
        @DisplayName("should not verify against a different password")
        void shouldNotVerifyDifferentPassword() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("bcryptuser2", "correctPassword1", "Bcrypt User 2")))
                    .andExpect(status().isCreated());

            Optional<User> user = userRepository.findByUsername("bcryptuser2");
            assertThat(user).isPresent();

            assertThat(passwordEncoder.matches("wrongPassword1", user.get().getPassword())).isFalse();
        }
    }

    // ── AC4: Login with correct credentials -> 200 + token ───────────────

    @Nested
    @DisplayName("AC4: POST /api/auth/login with correct credentials")
    class LoginCorrectCredentials {

        @Test
        @DisplayName("should return 200 with token and expiresIn")
        void shouldReturn200WithTokenAndExpiresIn() throws Exception {
            // Register user first
            registerUser("loginuser", "password123", "Login User");

            // Login
            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("loginuser", "password123")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.token").isNotEmpty())
                    .andExpect(jsonPath("$.expiresIn").isNumber());
        }

        @Test
        @DisplayName("should return a valid JWT token that can be verified")
        void shouldReturnValidJwtToken() throws Exception {
            registerUser("jwtverify", "password123", "JWT Verify User");

            MvcResult result = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("jwtverify", "password123")))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode body = objectMapper.readTree(result.getResponse().getContentAsString());
            String token = body.get("token").asText();

            assertThat(token).isNotBlank();
            assertThat(jwtTokenProvider.validateToken(token)).isTrue();
        }

        @Test
        @DisplayName("should return expiresIn as 86400 (24 hours in seconds)")
        void shouldReturnExpiresIn86400() throws Exception {
            registerUser("expiryuser", "password123", "Expiry User");

            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("expiryuser", "password123")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.expiresIn").value(86400));
        }
    }

    // ── AC5: Login with wrong password -> 401 ────────────────────────────

    @Nested
    @DisplayName("AC5: POST /api/auth/login with wrong password")
    class LoginWrongPassword {

        @Test
        @DisplayName("should return 401 Unauthorized when password is wrong")
        void shouldReturn401WhenPasswordIsWrong() throws Exception {
            registerUser("wrongpwduser", "correctPassword1", "Wrong Pwd User");

            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("wrongpwduser", "wrongPassword1")))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ── AC6: Login with non-existent username -> 401 ─────────────────────

    @Nested
    @DisplayName("AC6: POST /api/auth/login with non-existent username")
    class LoginNonExistentUsername {

        @Test
        @DisplayName("should return 401 Unauthorized when username does not exist")
        void shouldReturn401WhenUsernameDoesNotExist() throws Exception {
            mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("nonexistent_user", "password123")))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should not distinguish between non-existent user and wrong password (BR7)")
        void shouldNotDistinguishBetweenNonExistentAndWrongPassword() throws Exception {
            registerUser("existinguser", "password123", "Existing User");

            // Wrong password
            MvcResult wrongPwdResult = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("existinguser", "wrongpassword")))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            // Non-existent user
            MvcResult nonExistResult = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("ghostuser", "password123")))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            // Both should return 401 — same status code
            assertThat(wrongPwdResult.getResponse().getStatus())
                    .isEqualTo(nonExistResult.getResponse().getStatus());
        }
    }

    // ── AC7: GET /api/auth/me with valid token -> 200 ────────────────────

    @Nested
    @DisplayName("AC7: GET /api/auth/me with valid token")
    class GetMeWithValidToken {

        @Test
        @DisplayName("should return 200 with id, username, displayName")
        void shouldReturn200WithUserInfo() throws Exception {
            String token = registerAndLogin("meuser", "password123", "Me User");

            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.id").isNumber())
                    .andExpect(jsonPath("$.username").value("meuser"))
                    .andExpect(jsonPath("$.displayName").value("Me User"));
        }

        @Test
        @DisplayName("should not return password in /me response")
        void shouldNotReturnPasswordInMeResponse() throws Exception {
            String token = registerAndLogin("nopwdme", "password123", "No Pwd Me");

            MvcResult result = mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andReturn();

            String body = result.getResponse().getContentAsString();
            JsonNode json = objectMapper.readTree(body);
            assertThat(json.has("password")).isFalse();
        }
    }

    // ── AC8: GET /api/auth/me without Authorization header -> 401 ────────

    @Nested
    @DisplayName("AC8: GET /api/auth/me without Authorization header")
    class GetMeWithoutAuthHeader {

        @Test
        @DisplayName("should return 401 when no Authorization header is provided")
        void shouldReturn401WithoutAuthHeader() throws Exception {
            mockMvc.perform(get(ME_URL))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ── AC9: GET /api/auth/me with expired token -> 401 ──────────────────

    @Nested
    @DisplayName("AC9: GET /api/auth/me with expired token")
    class GetMeWithExpiredToken {

        @Test
        @DisplayName("should return 401 when token is expired")
        void shouldReturn401WithExpiredToken() throws Exception {
            // Register a user to get a valid user ID
            registerUser("expireduser", "password123", "Expired User");
            Optional<User> user = userRepository.findByUsername("expireduser");
            assertThat(user).isPresent();

            // Build an expired token manually
            SecretKey key = Keys.hmacShaKeyFor(jwtSecret.getBytes(StandardCharsets.UTF_8));
            String expiredToken = Jwts.builder()
                    .subject(String.valueOf(user.get().getId()))
                    .issuedAt(new Date(System.currentTimeMillis() - 200_000))
                    .expiration(new Date(System.currentTimeMillis() - 100_000)) // expired 100s ago
                    .signWith(key)
                    .compact();

            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + expiredToken))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ── AC10: GET /api/auth/me with malformed token -> 401 ───────────────

    @Nested
    @DisplayName("AC10: GET /api/auth/me with malformed token")
    class GetMeWithMalformedToken {

        @Test
        @DisplayName("should return 401 with completely invalid token string")
        void shouldReturn401WithInvalidTokenString() throws Exception {
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer not.a.valid.jwt.token"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 with random string as token")
        void shouldReturn401WithRandomString() throws Exception {
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer randomgarbage123"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 with empty Bearer value")
        void shouldReturn401WithEmptyBearerValue() throws Exception {
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer "))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 with wrong auth scheme (Basic instead of Bearer)")
        void shouldReturn401WithWrongAuthScheme() throws Exception {
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Basic dXNlcjpwYXNz"))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ── AC11: Register with username <3 or >50 chars -> 400 ──────────────

    @Nested
    @DisplayName("AC11: Register with username length violations")
    class RegisterUsernameLengthViolations {

        @Test
        @DisplayName("should return 400 when username is 2 chars (below minimum 3)")
        void shouldReturn400WhenUsernameTooShort() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("ab", "password123", "Short Name User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username is 1 char")
        void shouldReturn400WhenUsernameSingleChar() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("a", "password123", "Single Char User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username is empty string")
        void shouldReturn400WhenUsernameEmpty() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("", "password123", "Empty User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username is 51 chars (above maximum 50)")
        void shouldReturn400WhenUsernameTooLong() throws Exception {
            String username51 = "a".repeat(51);
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson(username51, "password123", "Long Name User")))
                    .andExpect(status().isBadRequest());
        }
    }

    // ── AC12: Register with password <8 chars -> 400 ─────────────────────

    @Nested
    @DisplayName("AC12: Register with password too short")
    class RegisterPasswordTooShort {

        @Test
        @DisplayName("should return 400 when password is 7 chars (below minimum 8)")
        void shouldReturn400WhenPassword7Chars() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("shortpwd", "1234567", "Short Pwd User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when password is 1 char")
        void shouldReturn400WhenPasswordSingleChar() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("shortpwd2", "x", "Short Pwd User 2")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when password is empty")
        void shouldReturn400WhenPasswordEmpty() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("emptypwd", "", "Empty Pwd User")))
                    .andExpect(status().isBadRequest());
        }
    }

    // ── AC13: Register with empty or >100 char displayName -> 400 ────────

    @Nested
    @DisplayName("AC13: Register with displayName violations")
    class RegisterDisplayNameViolations {

        @Test
        @DisplayName("should return 400 when displayName is empty string")
        void shouldReturn400WhenDisplayNameEmpty() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("emptydisplay", "password123", "")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when displayName exceeds 100 chars")
        void shouldReturn400WhenDisplayNameTooLong() throws Exception {
            String displayName101 = "D".repeat(101);
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("longdisplay", "password123", displayName101)))
                    .andExpect(status().isBadRequest());
        }
    }

    // ── AC14: Register with non-alphanumeric username -> 400 ─────────────

    @Nested
    @DisplayName("AC14: Register with invalid username characters")
    class RegisterInvalidUsernameChars {

        @Test
        @DisplayName("should return 400 when username contains spaces")
        void shouldReturn400WhenUsernameContainsSpaces() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("has space", "password123", "Space User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username contains special characters (@)")
        void shouldReturn400WhenUsernameContainsAt() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("user@name", "password123", "At User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username contains hyphen")
        void shouldReturn400WhenUsernameContainsHyphen() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("user-name", "password123", "Hyphen User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username contains dot")
        void shouldReturn400WhenUsernameContainsDot() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("user.name", "password123", "Dot User")))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("should return 400 when username contains unicode characters")
        void shouldReturn400WhenUsernameContainsUnicode() throws Exception {
            mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"username\":\"\\u4e2d\\u6587user\",\"password\":\"password123\",\"displayName\":\"Unicode User\"}"))
                    .andExpect(status().isBadRequest());
        }
    }

    // ── End-to-end flow tests ────────────────────────────────────────────

    @Nested
    @DisplayName("End-to-end auth flow")
    class EndToEndFlow {

        @Test
        @DisplayName("should complete full register -> login -> me flow successfully")
        void shouldCompleteFullAuthFlow() throws Exception {
            // Step 1: Register
            MvcResult registerResult = mockMvc.perform(post(REGISTER_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(registerJson("flowuser", "password123", "Flow User")))
                    .andExpect(status().isCreated())
                    .andReturn();

            JsonNode registerBody = objectMapper.readTree(registerResult.getResponse().getContentAsString());
            long userId = registerBody.get("id").asLong();
            assertThat(userId).isGreaterThan(0);

            // Step 2: Login
            MvcResult loginResult = mockMvc.perform(post(LOGIN_URL)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(loginJson("flowuser", "password123")))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode loginBody = objectMapper.readTree(loginResult.getResponse().getContentAsString());
            String token = loginBody.get("token").asText();
            long expiresIn = loginBody.get("expiresIn").asLong();
            assertThat(token).isNotBlank();
            assertThat(expiresIn).isPositive();

            // Step 3: Get current user with token
            mockMvc.perform(get(ME_URL)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.id").value(userId))
                    .andExpect(jsonPath("$.username").value("flowuser"))
                    .andExpect(jsonPath("$.displayName").value("Flow User"));
        }
    }
}

