package com.taskflow.service;

import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.LoginResponse;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.dto.UserResponse;
import com.taskflow.entity.User;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * Unit tests for AuthService.
 *
 * Tests the business logic for:
 * - register: validates uniqueness, encodes password with bcrypt, saves user, returns UserResponse
 * - login: verifies credentials, generates JWT, returns LoginResponse
 * - getCurrentUser: retrieves user by ID, returns UserResponse
 *
 * Uses Mockito to mock dependencies (UserRepository, PasswordEncoder, JwtTokenProvider).
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("AuthService Unit Tests")
class AuthServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private JwtTokenProvider jwtTokenProvider;

    @InjectMocks
    private AuthService authService;

    private RegisterRequest validRegisterRequest;
    private LoginRequest validLoginRequest;
    private User savedUser;

    @BeforeEach
    void setUp() {
        validRegisterRequest = new RegisterRequest();
        validRegisterRequest.setUsername("testuser");
        validRegisterRequest.setPassword("password123");
        validRegisterRequest.setDisplayName("Test User");

        validLoginRequest = new LoginRequest();
        validLoginRequest.setUsername("testuser");
        validLoginRequest.setPassword("password123");

        savedUser = new User();
        savedUser.setId(1L);
        savedUser.setUsername("testuser");
        savedUser.setPassword("$2a$10$hashedPasswordValue");
        savedUser.setDisplayName("Test User");
    }

    // ── register ─────────────────────────────────────────────────────────

    @Nested
    @DisplayName("register()")
    class Register {

        @Test
        @DisplayName("should encode password with bcrypt before saving")
        void shouldEncodePasswordBeforeSaving() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode("password123")).thenReturn("$2a$10$encodedHash");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(1L);
                return user;
            });

            authService.register(validRegisterRequest);

            ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(userCaptor.capture());
            assertThat(userCaptor.getValue().getPassword()).isEqualTo("$2a$10$encodedHash");
            verify(passwordEncoder).encode("password123");
        }

        @Test
        @DisplayName("should return UserResponse with id, username, displayName")
        void shouldReturnUserResponse() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$hashed");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(42L);
                return user;
            });

            UserResponse response = authService.register(validRegisterRequest);

            assertThat(response).isNotNull();
            assertThat(response.getId()).isEqualTo(42L);
            assertThat(response.getUsername()).isEqualTo("testuser");
            assertThat(response.getDisplayName()).isEqualTo("Test User");
        }

        @Test
        @DisplayName("should throw exception when username already exists")
        void shouldThrowWhenUsernameExists() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));

            assertThatThrownBy(() -> authService.register(validRegisterRequest))
                    .isInstanceOf(RuntimeException.class);

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should save user with correct username and displayName")
        void shouldSaveUserWithCorrectFields() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
            when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$hashed");
            when(userRepository.save(any(User.class))).thenAnswer(inv -> {
                User user = inv.getArgument(0);
                user.setId(1L);
                return user;
            });

            authService.register(validRegisterRequest);

            ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(userCaptor.capture());
            User captured = userCaptor.getValue();
            assertThat(captured.getUsername()).isEqualTo("testuser");
            assertThat(captured.getDisplayName()).isEqualTo("Test User");
        }
    }

    // ── login ────────────────────────────────────────────────────────────

    @Nested
    @DisplayName("login()")
    class Login {

        @Test
        @DisplayName("should return LoginResponse with token and expiresIn on success")
        void shouldReturnLoginResponseOnSuccess() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches("password123", "$2a$10$hashedPasswordValue")).thenReturn(true);
            when(jwtTokenProvider.generateToken(1L)).thenReturn("jwt.token.here");

            LoginResponse response = authService.login(validLoginRequest);

            assertThat(response).isNotNull();
            assertThat(response.getToken()).isEqualTo("jwt.token.here");
            assertThat(response.getExpiresIn()).isPositive();
        }

        @Test
        @DisplayName("should throw exception when username does not exist")
        void shouldThrowWhenUsernameNotFound() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());

            assertThatThrownBy(() -> authService.login(validLoginRequest))
                    .isInstanceOf(RuntimeException.class);
        }

        @Test
        @DisplayName("should throw exception when password is wrong")
        void shouldThrowWhenPasswordIsWrong() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches("password123", "$2a$10$hashedPasswordValue")).thenReturn(false);

            assertThatThrownBy(() -> authService.login(validLoginRequest))
                    .isInstanceOf(RuntimeException.class);

            verify(jwtTokenProvider, never()).generateToken(any());
        }

        @Test
        @DisplayName("should generate token using the user's ID")
        void shouldGenerateTokenWithUserId() {
            when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
            when(passwordEncoder.matches(anyString(), anyString())).thenReturn(true);
            when(jwtTokenProvider.generateToken(1L)).thenReturn("token");

            authService.login(validLoginRequest);

            verify(jwtTokenProvider).generateToken(1L);
        }
    }

    // ── getCurrentUser ───────────────────────────────────────────────────

    @Nested
    @DisplayName("getCurrentUser()")
    class GetCurrentUser {

        @Test
        @DisplayName("should return UserResponse when user exists")
        void shouldReturnUserResponseWhenUserExists() {
            when(userRepository.findById(1L)).thenReturn(Optional.of(savedUser));

            UserResponse response = authService.getCurrentUser(1L);

            assertThat(response).isNotNull();
            assertThat(response.getId()).isEqualTo(1L);
            assertThat(response.getUsername()).isEqualTo("testuser");
            assertThat(response.getDisplayName()).isEqualTo("Test User");
        }

        @Test
        @DisplayName("should throw exception when user not found by ID")
        void shouldThrowWhenUserNotFoundById() {
            when(userRepository.findById(999L)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> authService.getCurrentUser(999L))
                    .isInstanceOf(RuntimeException.class);
        }
    }

    // ── Contract: method signatures ──────────────────────────────────────

    @Test
    @DisplayName("Contract: AuthService has register, login, getCurrentUser methods")
    void contractMethodsExist() throws NoSuchMethodException {
        assertThat(AuthService.class.getMethod("register", RegisterRequest.class)
                .getReturnType()).isEqualTo(UserResponse.class);
        assertThat(AuthService.class.getMethod("login", LoginRequest.class)
                .getReturnType()).isEqualTo(LoginResponse.class);
        assertThat(AuthService.class.getMethod("getCurrentUser", Long.class)
                .getReturnType()).isEqualTo(UserResponse.class);
    }
