package com.taskflow.dto;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Validation tests for RegisterRequest DTO.
 * Uses Jakarta Validation directly (no Spring context needed).
 *
 * Validates:
 * - username: 3-50 chars, pattern ^[a-zA-Z0-9_]+$ (AC11, AC14)
 * - password: min 8 chars (AC12)
 * - displayName: 1-100 chars (AC13)
 */
@DisplayName("RegisterRequest Validation Tests")
class RegisterRequestValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUp() {
        try (ValidatorFactory factory = Validation.buildDefaultValidatorFactory()) {
            validator = factory.getValidator();
        }
    }

    private RegisterRequest validRequest() {
        RegisterRequest request = new RegisterRequest();
        request.setUsername("valid_user");
        request.setPassword("password123");
        request.setDisplayName("Valid User");
        return request;
    }

    // ── Username validation ──────────────────────────────────────────────

    @Nested
    @DisplayName("Username validation")
    class UsernameValidation {

        @Test
        @DisplayName("Valid username (alphanumeric + underscore, 3-50 chars) passes")
        void validUsernamePasses() {
            RegisterRequest request = validRequest();
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username at minimum boundary (3 chars) passes")
        void usernameMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("abc");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username at maximum boundary (50 chars) passes")
        void usernameMaxBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("a".repeat(50));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username below minimum (2 chars) fails")
        void usernameBelowMinFails() {
            RegisterRequest request = validRequest();
            request.setUsername("ab");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username above maximum (51 chars) fails")
        void usernameAboveMaxFails() {
            RegisterRequest request = validRequest();
            request.setUsername("a".repeat(51));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null username fails")
        void nullUsernameFails() {
            RegisterRequest request = validRequest();
            request.setUsername(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty username fails")
        void emptyUsernameFails() {
            RegisterRequest request = validRequest();
            request.setUsername("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with spaces fails")
        void usernameWithSpacesFails() {
            RegisterRequest request = validRequest();
            request.setUsername("has space");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with special characters fails")
        void usernameWithSpecialCharsFails() {
            RegisterRequest request = validRequest();
            request.setUsername("user@name!");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with hyphen fails")
        void usernameWithHyphenFails() {
            RegisterRequest request = validRequest();
            request.setUsername("user-name");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Username with digits only passes")
        void usernameWithDigitsOnlyPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("12345");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Username with underscores passes")
        void usernameWithUnderscoresPasses() {
            RegisterRequest request = validRequest();
            request.setUsername("user_name_123");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── Password validation ──────────────────────────────────────────────

    @Nested
    @DisplayName("Password validation")
    class PasswordValidation {

        @Test
        @DisplayName("Password at minimum boundary (8 chars) passes")
        void passwordMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setPassword("12345678");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Password below minimum (7 chars) fails")
        void passwordBelowMinFails() {
            RegisterRequest request = validRequest();
            request.setPassword("1234567");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty password fails")
        void emptyPasswordFails() {
            RegisterRequest request = validRequest();
            request.setPassword("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null password fails")
        void nullPasswordFails() {
            RegisterRequest request = validRequest();
            request.setPassword(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Long password (100+ chars) passes")
        void longPasswordPasses() {
            RegisterRequest request = validRequest();
            request.setPassword("a".repeat(200));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── DisplayName validation ───────────────────────────────────────────

    @Nested
    @DisplayName("DisplayName validation")
    class DisplayNameValidation {

        @Test
        @DisplayName("DisplayName at minimum boundary (1 char) passes")
        void displayNameMinBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("A");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("DisplayName at maximum boundary (100 chars) passes")
        void displayNameMaxBoundaryPasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("D".repeat(100));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("DisplayName above maximum (101 chars) fails")
        void displayNameAboveMaxFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName("D".repeat(101));
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty displayName fails")
        void emptyDisplayNameFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName("");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Null displayName fails")
        void nullDisplayNameFails() {
            RegisterRequest request = validRequest();
            request.setDisplayName(null);
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("DisplayName with unicode characters passes")
        void displayNameWithUnicodePasses() {
            RegisterRequest request = validRequest();
            request.setDisplayName("Test User Name");
            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }
    }

    // ── Contract: field types ────────────────────────────────────────────

    @Test
    @DisplayName("Contract: RegisterRequest has username, password, displayName getters/setters")
    void contractFieldsExist() throws NoSuchMethodException {
        assertThat(RegisterRequest.class.getMethod("getUsername").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("getPassword").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("getDisplayName").getReturnType()).isEqualTo(String.class);
        assertThat(RegisterRequest.class.getMethod("setUsername", String.class)).isNotNull();
        assertThat(RegisterRequest.class.getMethod("setPassword", String.class)).isNotNull();
        assertThat(RegisterRequest.class.getMethod("setDisplayName", String.class)).isNotNull();
    }
}

