package com.taskflow.dto;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Contract tests for Auth-related DTOs.
 *
 * Verifies that the following DTOs exist with expected fields and types:
 * - LoginRequest: username (String), password (String)
 * - LoginResponse: token (String), expiresIn (long)
 * - UserResponse: id (long), username (String), displayName (String)
 * - RegisterRequest: username (String), password (String), displayName (String)
 *
 * These tests ensure the DTO contract matches what the controller and service expect.
 */
@DisplayName("Auth DTO Contract Tests")
class AuthDtoContractTest {

    // ── LoginRequest ─────────────────────────────────────────────────────

    @Nested
    @DisplayName("LoginRequest")
    class LoginRequestContract {

        @Test
        @DisplayName("should have username field (String)")
        void shouldHaveUsernameField() throws NoSuchMethodException {
            assertThat(LoginRequest.class.getMethod("getUsername").getReturnType()).isEqualTo(String.class);
            assertThat(LoginRequest.class.getMethod("setUsername", String.class)).isNotNull();
        }

        @Test
        @DisplayName("should have password field (String)")
        void shouldHavePasswordField() throws NoSuchMethodException {
            assertThat(LoginRequest.class.getMethod("getPassword").getReturnType()).isEqualTo(String.class);
            assertThat(LoginRequest.class.getMethod("setPassword", String.class)).isNotNull();
        }

        @Test
        @DisplayName("should be instantiable with no-args constructor")
        void shouldBeInstantiable() throws Exception {
            LoginRequest request = LoginRequest.class.getDeclaredConstructor().newInstance();
            assertThat(request).isNotNull();
        }

        @Test
        @DisplayName("should store and retrieve values correctly")
        void shouldStoreAndRetrieveValues() {
            LoginRequest request = new LoginRequest();
            request.setUsername("testuser");
            request.setPassword("testpass");

            assertThat(request.getUsername()).isEqualTo("testuser");
            assertThat(request.getPassword()).isEqualTo("testpass");
        }
    }

    // ── LoginResponse ────────────────────────────────────────────────────

    @Nested
    @DisplayName("LoginResponse")
