            Class<?> returnType = LoginResponse.class.getMethod("getExpiresIn").getReturnType();
            // Accept both long and Long
            assertThat(returnType == long.class || returnType == Long.class).isTrue();
        }

        @Test
        @DisplayName("should be instantiable")
        void shouldBeInstantiable() throws Exception {
            LoginResponse response = LoginResponse.class.getDeclaredConstructor().newInstance();
            assertThat(response).isNotNull();
        }
    }

